import sys

class Solution:
    def minWindowSubsequence(self, S: str, T: str) -> int:
        m, n = len(S), len(T)
        dp = [[m + 1] * (n + 1) for _ in range(m + 1)]
        dp[0][0] = 0
        for i in range(1, m + 1):
            for j in range(n + 1):
                dp[i][j] = dp[i - 1][j]
                if j > 0 and i > 0 and S[i - 1] == T[j - 1]:
                    dp[i][j] = min(dp[i][j], dp[i - 1][j - 1] + 1)
        ans = dp[m][n]
        return ans if ans <= m else -1

