#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int minWindowSubsequence(string S, string T) {
        int m = S.size(), n = T.size();
        vector<vector<int>> dp(m + 1, vector<int>(n + 1, m + 1));
        dp[0][0] = 0;
        for (int i = 1; i <= m; i++) {
            for (int j = 0; j <= n; j++) {
                dp[i][j] = dp[i - 1][j];
                if (j > 0 && i > 0 && S[i - 1] == T[j - 1]) {
                    dp[i][j] = min(dp[i][j], dp[i - 1][j - 1] + 1);
                }
            }
        }
        int ans = dp[m][n];
        return ans <= m ? ans : -1;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    string S;
    cin >> S;
    int m;
    if (!(cin >> m)) return 0;
    string T;
    cin >> T;
    Solution sol;
    int ans = sol.minWindowSubsequence(S, T);
    cout << ans << '\n';
    return 0;
}
